import { Outlet, Link } from "react-router-dom";
import { makeStyles } from "@material-ui/core/styles";
import { NavLink } from "react-router-dom";
import "./Home.css";
import sa from "./sa.svg";

const useStyles = makeStyles((theme) => ({
  options: {
    marginLeft: "40px",
    color: "white",
  },
}));

const Header = (props) => {

  return(

  <header id="header">
      <div className="container">
          <div className="content">
              <NavLink to="/" className="home">Logo</NavLink>
              <nav>
                  <ul>
                      <li>
                          <NavLink to="/about" >Yellow</NavLink>
                      </li>
                      <li>
                          <NavLink to="/work" >Red</NavLink>
                      </li>
                      <li>
                          <NavLink to="/art">Green</NavLink>
                      </li>
                      <li>
                          <NavLink to="/contact">Blue</NavLink>
                      </li>

                  </ul>
              </nav>
          </div>
      </div>
  </header>

)}
export default Header;
